mapper.select:
/* adm-system-menuhistory-sql-oracle.xml - selectMenuHistoryCount */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT MEHS.MEHSKEY , MEHS.IPADDR , MEHS.URKEY , UR.URNM , MEHS.APKEY , MEHS.MEKEY , MUDT.DISPLAYMSG AS MENM , MEHS.ACSDT , MEHS.ACSDATE FROM TADMIN_INFO_URMEHS MEHS INNER JOIN TADMIN_MST_UR UR ON MEHS.URKEY = UR.URKEY INNER JOIN TADMIN_MST_ME MENU ON MEHS.MEKEY = MENU.MEKEY INNER JOIN TADMIN_MST_MULAAPMSG_HD MUHD ON MENU.MENM = MUHD.MULAAPMSGHDKEY INNER JOIN TADMIN_MST_MULAAPMSG_DT MUDT ON MUDT.MULAAPMSGHDKEY = MUHD.MULAAPMSGHDKEY AND MUDT.LAKEY = #{slakey} WHERE 1 = 1
AND #{SEARCH_CONDITION}
ORDER BY MEHS.MEHSKEY DESC #{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.insert:
/* adm-system-menuhistory-sql-oracle.xml - insertMeHistory */
INSERT INTO TADMIN_INFO_URMEHS (
	  	   MEHSKEY
	     , IPADDR
	     , URKEY
	     , APKEY
	     , MEKEY
	     , ACSDT
	     , ACSDATE
	     , INSERTDATE
) VALUES (
		   #{mehskey}
		 , #{ipaddr}
		 , #{surkey}
		 , #{apkey}
		 , #{mekey}
		 , SUBSTR(#{sysdate}, 0, 8)
		 , #{sysdate}
		 , #{sysdate}
		 )

mapper.select:
/* adm-system-menuhistory-sql-oracle.xml - selectTotalHistory */ SELECT MEHS.MEKEY , MUDT.DISPLAYMSG AS MENM , COUNT(1) AS CNT FROM TADMIN_INFO_URMEHS MEHS INNER JOIN TADMIN_MST_UR UR ON MEHS.URKEY = UR.URKEY INNER JOIN TADMIN_MST_ME MENU ON MEHS.MEKEY = MENU.MEKEY INNER JOIN TADMIN_MST_MULAAPMSG_HD MUHD ON MENU.MENM = MUHD.MULAAPMSGHDKEY INNER JOIN TADMIN_MST_MULAAPMSG_DT MUDT ON MUDT.MULAAPMSGHDKEY = MUHD.MULAAPMSGHDKEY AND MUDT.LAKEY = #{slakey} WHERE 1=1
AND #{SEARCH_CONDITION}
GROUP BY MEHS.MEKEY, MUDT.DISPLAYMSG ORDER BY CNT DESC, MEKEY
